VALUES
  ('social-worker-moex-06980', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '對於非營利組織的董（理）事會角色描述，下列何者錯誤？', '["董（理）事會具有信託責任，扮演機構受託人角色", "董（理）事會掌控機構運作的決策權", "董（理）事會成員的選任由機構董事長（或理事長）遴選任用", "董（理）事會對於機構的方案提供正式的合法性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "861375f44ec1", "answer_pdf_sha1": "a6b708cb0119", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06981', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '過去十幾年來，有越來越多組織逐漸重視員工服務福利的設計，許多雇主發現提供諮詢或輔導服務給員 工，協助他們解決一些問題，例如家庭問題、債務糾紛或藥酒癮問題等，是很好的投資。這樣的服務稱 為？', '["福利自助制度", "員工協助方案", "專案團隊督導", "績效管理服務"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "861375f44ec1", "answer_pdf_sha1": "a6b708cb0119", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06982', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '當人們經歷某個問題時便會產生某種需求，因此，需求評估是服務方案規劃過程相當重要的步驟之一， 下列那項關於需求評估的敘述是錯誤的？', '["需求的界定也可以藉由服務提供者是否提供足夠的服務來判定", "需求的界定不宜過於主觀，不適合透過有需要的人的說法來加以界定", "貧窮線的設定可以藉由家庭在購買日常生活必需品所能擁有的資源情況，來判定是否有需求", "當服務組織擴大服務的內容與範圍時，常會使得標的人口群的期待提高，進而影響需求的判定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "861375f44ec1", "answer_pdf_sha1": "a6b708cb0119", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06983', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '就組織結構的設計而言，有越來越多的管理者將傳統的組織結構做修正或改變，以達到更大彈性與團隊 合作，矩陣式組織便是其中一種結構，下列那項描述最不符合矩陣式組織的特點？', '["員工被賦予的主要職責是做為方案之間的溝通橋樑，以確保政策與程序的彼此相容", "假定員工為了達到生產力最適水準，通常需要超過一個學科以上的專業知識", "員工有超過一個以上的直接督導", "矩陣式組織注入了彈性，但也使組織變複雜，容易導致組織內部的權力衝突"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "861375f44ec1", "answer_pdf_sha1": "a6b708cb0119", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06984', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '管理者是組織運作與發展的核心人物，必須有能力瞭解組織的財務結構與妥善運用組織的財務資源，下 列關於組織財務資料的描述，何者錯誤？', '["組織的資產負債表需涵蓋整個會計年度的收入與支出的彙總結果", "彙整某一特定期間內的組織所有收入和利得後，再減去彙整後的所有費用與損失之結果，即為組織的 單站式（single-step）損益表", "組織的現金、有價證券、短期應收款項、存款等皆屬於流動資產", "組織的儲蓄存款與支票等皆應歸入現金的資產計算"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "861375f44ec1", "answer_pdf_sha1": "a6b708cb0119", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06985', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '近年所倡導之標竿計畫（beacon scheme），其檢視績效的4Cs，又有第五個C，對社會工作實務的運作更 深具意義，這5Cs不包括：', '["徵詢", "競爭", "統合", "合作"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "861375f44ec1", "answer_pdf_sha1": "a6b708cb0119", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06986', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '社工管理者相對於企業管理者應具備的技巧或能力中，最具有特色的是重視：', '["人力資源管理議題", "維持個人的均衡議題", "溝通議題", "社會和公共政策議題"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "861375f44ec1", "answer_pdf_sha1": "a6b708cb0119", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06987', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '一位主管能有效率與有效能的督導部屬人數，稱為？', '["集權幅度", "分權幅度", "控制幅度", "效能幅度"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "861375f44ec1", "answer_pdf_sha1": "a6b708cb0119", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06988', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '如果問：「我們現在做的事是該做的事嗎?」其所做的規劃是下列何種規劃？', '["近期規劃", "中期規劃", "長期規劃", "策略規劃"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "861375f44ec1", "answer_pdf_sha1": "a6b708cb0119", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06989', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '志工的運用一直是社會服務組織重要的人力資源來源，下列那項志工管理規則，最不符合「志願服務法」 相關條文之規定？', '["志工得要求獲得從事服務之完整資訊", "志工必須遵守「志願服務法」倫理守則之規定", "志工向受服務對象收取報酬，必須徵得服務機構之同意", "志願服務運用部門於必要時，得補助志工交通、誤餐及特殊保險等經費"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "861375f44ec1", "answer_pdf_sha1": "a6b708cb0119", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
